        """TAKE_PROFIT_MARKET via Algo Order API."""
        return self._algo_order(symbol, 'TAKE_PROFIT_MARKET', side, quantity, stop_price)

    def trailing_stop_market(self, symbol, side, quantity, callback_rate, activation_price=None):
        """
        TRAILING_STOP_MARKET via Algo Order API.

        Args:
            symbol: Pair (e.g., 'BTCUSDT')
            side: 'BUY' atau 'SELL'
            quantity: Jumlah qty
            callback_rate: % trailing (e.g., 1.0 = 1%)
            activation_price: Harga aktifasi trailing (opsional, None = aktif langsung)

        Returns:
            dict dengan algoId atau error
        """
        params = {
            'symbol': symbol,
            'side': side.upper(),
            'type': 'TRAILING_STOP_MARKET',
            'algoType': 'CONDITIONAL',
            'callbackRate': str(callback_rate),
            'quantity': str(quantity),
            'workingType': 'MARK_PRICE',
            'reduceOnly': 'true',
        }
        if activation_price is not None:
            params['activationPrice'] = str(activation_price)
        return self._post('/fapi/v1/algoOrder', params)

    def _algo_order(self, symbol, order_type, side, quantity, trigger_price):
        """Algo order (CONDITIONAL) via POST /fapi/v1/algoOrder."""
        return self._post('/fapi/v1/algoOrder', {
            'symbol': symbol,
            'side': side.upper(),
            'type': order_type,
            'algoType': 'CONDITIONAL',
            'triggerPrice': str(trigger_price),
            'quantity': str(quantity),
            'workingType': 'MARK_PRICE',
            'reduceOnly': 'true',
        })

    def cancel_algo_order(self, symbol, algo_id):
        return self._delete('/fapi/v1/algoOrder', {'symbol': symbol, 'algoId': algo_id})

    def cancel_all_algo_orders(self, symbol, algo_ids=None):
        """Cancel algo orders. Testnet gak ada list endpoint jadi butuh tracked IDs."""
        results = []
        if algo_ids:
            for aid in algo_ids:
                results.append(self.cancel_algo_order(symbol, aid))
        return results

    def cancel_order(self, symbol, order_id):
        return self._delete('/fapi/v1/order', {'symbol': symbol, 'orderId': order_id})

    def cancel_all_orders(self, symbol, algo_ids=None):
        """Cancel semua regular order + algo order buat 1 symbol."""
        regular = self._delete('/fapi/v1/allOpenOrders', {'symbol': symbol})
        self.cancel_all_algo_orders(symbol, algo_ids)
        return regular
